/**
 * Order Repository
 *
 * Data access layer for Order entities.
 * Provides tenant-scoped database operations with CRUD support.
 *
 * @module modules/order/order.repository
 *
 * @example
 * ```typescript
 * import { OrderRepository } from '@/modules/order/order.repository';
 *
 * const repo = container.resolve('OrderRepository');
 * const order = await repo.findByOrderNumber('org_123', 'ORD-20260201-ABC123');
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { PrismaClient, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';
import { notDeleted } from '@/config/database';

import type {
  Order,
  OrderWithRelations,
  OrderStatus,
  OrderType,
  ListOrdersQuery,
  OrderItem,
  OrderItemStatus,
} from '@/modules/order/order.types';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Array of entities */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Order summary for list displays
 */
export interface OrderSummary {
  /** Order ID */
  id: string;
  /** Order number */
  orderNumber: string;
  /** Order status */
  status: OrderStatus;
  /** Order type */
  type: OrderType;
  /** Table number */
  tableNumber: string | null;
  /** Item count */
  itemCount: number;
  /** Total amount */
  totalAmount: number;
  /** Creation timestamp */
  createdAt: Date;
}

/**
 * Create order data (input for repository)
 */
export interface CreateOrderData {
  orderNumber: string;
  branchId?: string | null;
  tableId?: string | null;
  customerId?: string | null;
  staffId?: string | null;
  status?: OrderStatus;
  type?: OrderType;
  subtotal: number;
  taxAmount: number;
  discountAmount?: number;
  totalAmount: number;
  currency?: string;
  notes?: string | null;
}

/**
 * Update order data (input for repository)
 */
export interface UpdateOrderData {
  staffId?: string | null;
  status?: OrderStatus;
  notes?: string | null;
  confirmedAt?: Date | null;
  preparedAt?: Date | null;
  deliveredAt?: Date | null;
  completedAt?: Date | null;
  cancelledAt?: Date | null;
  cancelReason?: string | null;
}

/**
 * Create order item data (input for repository)
 */
export interface CreateOrderItemData {
  productId: string;
  variantId?: string | null;
  productName: string;
  variantName?: string | null;
  quantity: number;
  unitPrice: number;
  totalPrice: number;
  modifiers?: Prisma.JsonValue;
  notes?: string | null;
  status?: OrderItemStatus;
}

/**
 * Update order item data (input for repository)
 */
export interface UpdateOrderItemData {
  quantity?: number;
  totalPrice?: number;
  notes?: string | null;
  status?: OrderItemStatus;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const DEFAULT_PER_PAGE = 20;
const MAX_PER_PAGE = 100;

// -----------------------------------------------------------------------------
// Order Repository
// -----------------------------------------------------------------------------

/**
 * Repository for Order entity operations.
 *
 * Handles all database operations for orders including:
 * - CRUD operations with tenant isolation
 * - Order number lookups within organizations
 * - Status management
 * - Order items management
 *
 * @remarks
 * All operations require organizationId for tenant isolation.
 *
 * @example
 * ```typescript
 * @injectable()
 * class OrderService {
 *   constructor(
 *     @inject('OrderRepository') private repo: OrderRepository
 *   ) {}
 *
 *   async getByOrderNumber(orgId: string, orderNumber: string) {
 *     return this.repo.findByOrderNumber(orgId, orderNumber);
 *   }
 * }
 * ```
 */
@injectable()
export class OrderRepository {
  constructor(
    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all orders for an organization with pagination and filtering
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param params - Query parameters (pagination, sorting, filtering)
   * @returns Paginated list of orders
   *
   * @example
   * ```typescript
   * const result = await repo.findAll('org_123', {
   *   status: 'PENDING',
   *   page: 1,
   *   perPage: 20,
   * });
   * ```
   */
  async findAll(
    organizationId: string,
    params: ListOrdersQuery = {}
  ): Promise<PaginatedResult<Order>> {
    const {
      status,
      type,
      branchId,
      tableId,
      customerId,
      dateFrom,
      dateTo,
      search,
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.OrderWhereInput = {
      organizationId,
      ...(status !== undefined && { status }),
      ...(type !== undefined && { type }),
      ...(branchId !== undefined && { branchId }),
      ...(tableId !== undefined && { tableId }),
      ...(customerId !== undefined && { customerId }),
      ...(dateFrom && { createdAt: { gte: new Date(dateFrom) } }),
      ...(dateTo && { createdAt: { lte: new Date(dateTo) } }),
      ...(search && {
        orderNumber: { contains: search, mode: 'insensitive' },
      }),
    };

    // Build orderBy clause
    const orderBy: Prisma.OrderOrderByWithRelationInput = { [sortBy]: sortOrder };

    // Execute count and find in parallel
    const [total, data] = await Promise.all([
      this.prisma.order.count({ where }),
      this.prisma.order.findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: data as Order[],
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds all orders as summaries (for quick displays)
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param params - Optional filtering params
   * @returns Array of order summaries
   */
  async findAllSummaries(
    organizationId: string,
    params: Partial<ListOrdersQuery> = {}
  ): Promise<OrderSummary[]> {
    const { status, type, tableId } = params;

    const where: Prisma.OrderWhereInput = {
      organizationId,
      ...(status !== undefined && { status }),
      ...(type !== undefined && { type }),
      ...(tableId !== undefined && { tableId }),
    };

    const orders = await this.prisma.order.findMany({
      where,
      select: {
        id: true,
        orderNumber: true,
        status: true,
        type: true,
        totalAmount: true,
        createdAt: true,
        table: {
          select: {
            number: true,
          },
        },
        _count: {
          select: {
            items: true,
          },
        },
      },
      orderBy: { createdAt: 'desc' },
    });

    return orders.map((order) => ({
      id: order.id,
      orderNumber: order.orderNumber,
      status: order.status as OrderStatus,
      type: order.type as OrderType,
      tableNumber: order.table?.number || null,
      itemCount: order._count.items,
      totalAmount: Number(order.totalAmount),
      createdAt: order.createdAt,
    }));
  }

  /**
   * Finds active orders (not completed or cancelled)
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param tableId - Optional table ID filter
   * @returns Array of active orders
   */
  async findActiveOrders(
    organizationId: string,
    tableId?: string
  ): Promise<Order[]> {
    const result = await this.prisma.order.findMany({
      where: {
        organizationId,
        status: {
          notIn: ['COMPLETED', 'CANCELLED'],
        },
        ...(tableId && { tableId }),
      },
      orderBy: { createdAt: 'desc' },
    });

    return result as Order[];
  }

  /**
   * Finds orders by status
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param status - Order status
   * @returns Array of orders
   */
  async findByStatus(organizationId: string, status: OrderStatus): Promise<Order[]> {
    const result = await this.prisma.order.findMany({
      where: {
        organizationId,
        status,
      },
      orderBy: { createdAt: 'asc' },
    });

    return result as Order[];
  }

  /**
   * Finds a order by ID with tenant isolation
   *
   * @param id - Order ID
   * @param organizationId - Organization ID for tenant isolation
   * @returns Order or null
   */
  async findById(id: string, organizationId: string): Promise<Order | null> {
    const result = await this.prisma.order.findFirst({
      where: { id, organizationId },
    });

    return result as Order | null;
  }

  /**
   * Finds a order by ID with relations
   *
   * @param id - Order ID
   * @param organizationId - Organization ID for tenant isolation
   * @param include - Relations to include
   * @returns Order with relations or null
   */
  async findByIdWithRelations(
    id: string,
    organizationId: string,
    include?: Array<'items' | 'table' | 'customer' | 'feedback'>
  ): Promise<OrderWithRelations | null> {
    const includeConfig: Prisma.OrderInclude = {};

    if (!include || include.length === 0) {
      // Default includes
      includeConfig.items = true;
      includeConfig.table = true;
    } else {
      if (include.includes('items')) includeConfig.items = true;
      if (include.includes('table')) includeConfig.table = true;
      if (include.includes('customer')) includeConfig.customer = true;
      if (include.includes('feedback')) includeConfig.feedback = true;
    }

    const result = await this.prisma.order.findFirst({
      where: { id, organizationId },
      include: includeConfig,
    });

    return result as OrderWithRelations | null;
  }

  /**
   * Finds a order by ID or throws
   *
   * @param id - Order ID
   * @param organizationId - Organization ID for tenant isolation
   * @returns Order
   * @throws {AppException} If not found
   */
  async findByIdOrThrow(id: string, organizationId: string): Promise<Order> {
    const order = await this.findById(id, organizationId);

    if (!order) {
      throw AppException.notFound('Order', id);
    }

    return order;
  }

  /**
   * Finds a order by order number within an organization
   *
   * @param organizationId - Organization ID for tenant isolation
   * @param orderNumber - Order number
   * @returns Order or null
   */
  async findByOrderNumber(organizationId: string, orderNumber: string): Promise<Order | null> {
    const result = await this.prisma.order.findFirst({
      where: { organizationId, orderNumber },
    });

    return result as Order | null;
  }

  /**
   * Checks if an order number exists within an organization
   *
   * @param organizationId - Organization ID
   * @param orderNumber - Order number to check
   * @returns True if number exists
   */
  async orderNumberExists(organizationId: string, orderNumber: string): Promise<boolean> {
    const count = await this.prisma.order.count({
      where: {
        organizationId,
        orderNumber,
      },
    });

    return count > 0;
  }

  /**
   * Counts orders for an organization
   *
   * @param organizationId - Organization ID
   * @param status - Optional status filter
   * @returns Count
   */
  async count(organizationId: string, status?: OrderStatus): Promise<number> {
    return this.prisma.order.count({
      where: {
        organizationId,
        ...(status !== undefined && { status }),
      },
    });
  }

  /**
   * Gets the next sequential order number for a day
   *
   * @param organizationId - Organization ID
   * @param datePrefix - Date prefix (YYYYMMDD)
   * @param prefix - Order number prefix (e.g., 'ORD')
   * @returns Next order number
   */
  async getNextOrderNumber(
    organizationId: string,
    datePrefix: string,
    prefix: string = 'ORD'
  ): Promise<string> {
    // Find the last order for this date prefix
    const lastOrder = await this.prisma.order.findFirst({
      where: {
        organizationId,
        orderNumber: {
          startsWith: `${prefix}-${datePrefix}`,
        },
      },
      orderBy: { createdAt: 'desc' },
      select: { orderNumber: true },
    });

    let sequence = 1;
    if (lastOrder) {
      // Extract sequence number from the last order number
      const parts = lastOrder.orderNumber.split('-');
      if (parts.length >= 3) {
        const lastSequence = parseInt(parts[2], 10);
        if (!isNaN(lastSequence)) {
          sequence = lastSequence + 1;
        }
      }
    }

    // Pad sequence to 4 digits
    const paddedSequence = sequence.toString().padStart(4, '0');
    return `${prefix}-${datePrefix}-${paddedSequence}`;
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new order with items
   *
   * @param organizationId - Organization ID for tenant association
   * @param data - Create data
   * @param items - Order items
   * @returns Created order with items
   */
  async create(
    organizationId: string,
    data: CreateOrderData,
    items: CreateOrderItemData[]
  ): Promise<Order> {
    const result = await this.prisma.order.create({
      data: {
        organizationId,
        orderNumber: data.orderNumber,
        branchId: data.branchId || null,
        tableId: data.tableId || null,
        customerId: data.customerId || null,
        staffId: data.staffId || null,
        status: data.status ?? 'PENDING',
        type: data.type ?? 'DINE_IN',
        subtotal: data.subtotal,
        taxAmount: data.taxAmount,
        discountAmount: data.discountAmount ?? 0,
        totalAmount: data.totalAmount,
        currency: data.currency ?? 'TRY',
        notes: data.notes || null,
        items: {
          create: items.map((item) => ({
            productId: item.productId,
            variantId: item.variantId || null,
            productName: item.productName,
            variantName: item.variantName || null,
            quantity: item.quantity,
            unitPrice: item.unitPrice,
            totalPrice: item.totalPrice,
            modifiers: item.modifiers || [],
            notes: item.notes || null,
            status: item.status ?? 'PENDING',
          })),
        },
      },
      include: {
        items: true,
      },
    });

    return result as unknown as Order;
  }

  /**
   * Updates an order
   *
   * @param id - Order ID
   * @param organizationId - Organization ID for tenant isolation
   * @param data - Update data
   * @returns Updated order
   * @throws {AppException} If not found
   */
  async update(
    id: string,
    organizationId: string,
    data: UpdateOrderData
  ): Promise<Order> {
    // Verify exists
    await this.findByIdOrThrow(id, organizationId);

    const result = await this.prisma.order.update({
      where: { id },
      data: {
        ...(data.staffId !== undefined && { staffId: data.staffId }),
        ...(data.status !== undefined && { status: data.status }),
        ...(data.notes !== undefined && { notes: data.notes }),
        ...(data.confirmedAt !== undefined && { confirmedAt: data.confirmedAt }),
        ...(data.preparedAt !== undefined && { preparedAt: data.preparedAt }),
        ...(data.deliveredAt !== undefined && { deliveredAt: data.deliveredAt }),
        ...(data.completedAt !== undefined && { completedAt: data.completedAt }),
        ...(data.cancelledAt !== undefined && { cancelledAt: data.cancelledAt }),
        ...(data.cancelReason !== undefined && { cancelReason: data.cancelReason }),
      },
    });

    return result as Order;
  }

  /**
   * Updates order status with appropriate timestamp
   *
   * @param id - Order ID
   * @param organizationId - Organization ID
   * @param status - New status
   * @param reason - Optional cancel reason
   * @returns Updated order
   */
  async updateStatus(
    id: string,
    organizationId: string,
    status: OrderStatus,
    reason?: string
  ): Promise<Order> {
    await this.findByIdOrThrow(id, organizationId);

    const now = new Date();
    const timestampField = this.getTimestampFieldForStatus(status);
    const updateData: Prisma.OrderUpdateInput = {
      status,
      ...(timestampField && { [timestampField]: now }),
      ...(status === 'CANCELLED' && reason && { cancelReason: reason }),
    };

    const result = await this.prisma.order.update({
      where: { id },
      data: updateData,
    });

    return result as Order;
  }

  /**
   * Recalculates order totals based on items
   *
   * @param id - Order ID
   * @param organizationId - Organization ID
   * @param taxRate - Tax rate percentage
   * @returns Updated order
   */
  async recalculateTotals(
    id: string,
    organizationId: string,
    taxRate: number = 10
  ): Promise<Order> {
    const order = await this.findByIdOrThrow(id, organizationId);

    // Get all items and calculate totals
    const items = await this.prisma.orderItem.findMany({
      where: { orderId: id },
    });

    const subtotal = items.reduce((sum, item) => sum + Number(item.totalPrice), 0);
    const discountAmount = Number(order.discountAmount);
    const taxAmount = (subtotal - discountAmount) * (taxRate / 100);
    const totalAmount = subtotal - discountAmount + taxAmount;

    const result = await this.prisma.order.update({
      where: { id },
      data: {
        subtotal: Math.round(subtotal * 100) / 100,
        taxAmount: Math.round(taxAmount * 100) / 100,
        totalAmount: Math.round(totalAmount * 100) / 100,
      },
    });

    return result as Order;
  }

  // ---------------------------------------------------------------------------
  // Order Item Operations
  // ---------------------------------------------------------------------------

  /**
   * Gets order items for an order
   *
   * @param orderId - Order ID
   * @returns Array of order items
   */
  async getOrderItems(orderId: string): Promise<OrderItem[]> {
    const items = await this.prisma.orderItem.findMany({
      where: { orderId },
      orderBy: { createdAt: 'asc' },
    });

    return items as OrderItem[];
  }

  /**
   * Adds an item to an order
   *
   * @param orderId - Order ID
   * @param item - Item data
   * @returns Created order item
   */
  async addOrderItem(orderId: string, item: CreateOrderItemData): Promise<OrderItem> {
    const result = await this.prisma.orderItem.create({
      data: {
        orderId,
        productId: item.productId,
        variantId: item.variantId || null,
        productName: item.productName,
        variantName: item.variantName || null,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        totalPrice: item.totalPrice,
        modifiers: item.modifiers || [],
        notes: item.notes || null,
        status: item.status ?? 'PENDING',
      },
    });

    return result as OrderItem;
  }

  /**
   * Updates an order item
   *
   * @param id - Order item ID
   * @param data - Update data
   * @returns Updated order item
   */
  async updateOrderItem(id: string, data: UpdateOrderItemData): Promise<OrderItem> {
    const result = await this.prisma.orderItem.update({
      where: { id },
      data: {
        ...(data.quantity !== undefined && { quantity: data.quantity }),
        ...(data.totalPrice !== undefined && { totalPrice: data.totalPrice }),
        ...(data.notes !== undefined && { notes: data.notes }),
        ...(data.status !== undefined && { status: data.status }),
      },
    });

    return result as OrderItem;
  }

  /**
   * Updates order item status
   *
   * @param id - Order item ID
   * @param status - New status
   * @returns Updated order item
   */
  async updateOrderItemStatus(id: string, status: OrderItemStatus): Promise<OrderItem> {
    const result = await this.prisma.orderItem.update({
      where: { id },
      data: { status },
    });

    return result as OrderItem;
  }

  /**
   * Removes an order item
   *
   * @param id - Order item ID
   */
  async removeOrderItem(id: string): Promise<void> {
    await this.prisma.orderItem.delete({
      where: { id },
    });
  }

  /**
   * Gets a specific order item
   *
   * @param id - Order item ID
   * @returns Order item or null
   */
  async getOrderItem(id: string): Promise<OrderItem | null> {
    const result = await this.prisma.orderItem.findUnique({
      where: { id },
    });

    return result as OrderItem | null;
  }

  /**
   * Gets a specific order item or throws
   *
   * @param id - Order item ID
   * @returns Order item
   * @throws {AppException} If not found
   */
  async getOrderItemOrThrow(id: string): Promise<OrderItem> {
    const item = await this.getOrderItem(id);

    if (!item) {
      throw AppException.notFound('OrderItem', id);
    }

    return item;
  }

  // ---------------------------------------------------------------------------
  // Statistics
  // ---------------------------------------------------------------------------

  /**
   * Gets order statistics for a period
   *
   * @param organizationId - Organization ID
   * @param startDate - Start date
   * @param endDate - End date
   * @returns Statistics object
   */
  async getStatistics(
    organizationId: string,
    startDate?: Date,
    endDate?: Date
  ): Promise<{
    totalOrders: number;
    byStatus: Record<OrderStatus, number>;
    byType: Record<OrderType, number>;
    totalRevenue: number;
    averageOrderValue: number;
  }> {
    const where: Prisma.OrderWhereInput = {
      organizationId,
      ...(startDate && { createdAt: { gte: startDate } }),
      ...(endDate && { createdAt: { lte: endDate } }),
    };

    // Get counts by status and type
    const [statusCounts, typeCounts, totalStats] = await Promise.all([
      this.prisma.order.groupBy({
        by: ['status'],
        where,
        _count: { _all: true },
      }),
      this.prisma.order.groupBy({
        by: ['type'],
        where,
        _count: { _all: true },
      }),
      this.prisma.order.aggregate({
        where: {
          ...where,
          status: 'COMPLETED',
        },
        _count: { _all: true },
        _sum: { totalAmount: true },
      }),
    ]);

    const byStatus = {} as Record<OrderStatus, number>;
    for (const item of statusCounts) {
      byStatus[item.status as OrderStatus] = item._count._all;
    }

    const byType = {} as Record<OrderType, number>;
    for (const item of typeCounts) {
      byType[item.type as OrderType] = item._count._all;
    }

    const totalRevenue = Number(totalStats._sum.totalAmount) || 0;
    const completedCount = totalStats._count._all || 0;
    const averageOrderValue = completedCount > 0 ? totalRevenue / completedCount : 0;

    return {
      totalOrders: statusCounts.reduce((sum, s) => sum + s._count._all, 0),
      byStatus,
      byType,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
      averageOrderValue: Math.round(averageOrderValue * 100) / 100,
    };
  }

  // ---------------------------------------------------------------------------
  // Helper Methods
  // ---------------------------------------------------------------------------

  /**
   * Gets the timestamp field name for a given status
   */
  private getTimestampFieldForStatus(status: OrderStatus): string | null {
    const statusToTimestamp: Record<OrderStatus, string | null> = {
      PENDING: null,
      CONFIRMED: 'confirmedAt',
      PREPARING: 'preparedAt',
      READY: 'preparedAt',
      DELIVERED: 'deliveredAt',
      COMPLETED: 'completedAt',
      CANCELLED: 'cancelledAt',
    };

    return statusToTimestamp[status];
  }
}
